// Enhanced application with security best practices
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security Middleware
app.use(helmet()); // Sets various HTTP headers for security

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Body parser with size limits
app.use(express.json({ limit: '10kb' }));

// Input validation helper
const validateQuery = (schema) => (req, res, next) => {
  try {
    // Example: validate query parameters
    const { limit, offset } = req.query;

    if (limit && (isNaN(limit) || limit < 0 || limit > 100)) {
      return res.status(400).json({ 
        error: 'Invalid limit parameter. Must be 0-100.' 
      });
    }

    if (offset && (isNaN(offset) || offset < 0)) {
      return res.status(400).json({ 
        error: 'Invalid offset parameter. Must be >= 0.' 
      });
    }

    next();
  } catch (error) {
    res.status(400).json({ error: 'Invalid request parameters.' });
  }
};

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users endpoint with input validation
app.get('/users', validateQuery(), (req, res) => {
  try {
    const limit = Math.min(parseInt(req.query.limit) || 10, 100);
    const offset = parseInt(req.query.offset) || 0;

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const paginatedUsers = users.slice(offset, offset + limit);

    res.json({ 
      data: paginatedUsers,
      total: users.length,
      limit,
      offset
    });
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Failed to fetch users' });
  }
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Endpoint not found' });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Avoid exposing internal error details to clients
  const status = err.status || 500;
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal server error' 
    : err.message;

  res.status(status).json({ error: message });
});

// Server startup with error handling
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Handle unhandled rejections
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled Rejection at:', promise, 'reason:', reason);
  // Optionally exit or send alert
});

module.exports = app;
```

