    // Don't expose sensitive data like emails in production
    const users = [
      { id: 1, name: 'Alice' }, // Removed email
      { id: 2, name: 'Bob' }     // Removed email
    ];

    // Optional: filter by ID if provided
    if (req.query.id) {
      const user = users.find(u => u.id === parseInt(req.query.id));
      return res.json(user || { error: 'User not found' });
    }

    res.json(users);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

